// App.js - Updated with Correct Navigation Menu
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './styles.css';

const API_URL = 'http://localhost:5001/api';

function App() {
  const [currentView, setCurrentView] = useState('home');
  const [user, setUser] = useState(null);
  const [posts, setPosts] = useState([]);
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [selectedPost, setSelectedPost] = useState(null);
  const [comments, setComments] = useState([]);
  const [commentText, setCommentText] = useState('');
  const [formData, setFormData] = useState({
    title: '',
    content: '',
    image: ''
  });
  const [loginData, setLoginData] = useState({ email: '', password: '' });
  const [registerData, setRegisterData] = useState({ name: '', email: '', password: '' });
  const [profileData, setProfileData] = useState({ name: '', bio: '' });

  // Configure axios
  const token = localStorage.getItem('token');
  if (token) {
    axios.defaults.headers.common['Authorization'] = token;
  }

  // Fetch data on load
  useEffect(() => {
    fetchPosts();
    if (token) {
      fetchUserProfile();
    }
  }, [token]);

  useEffect(() => {
    if (user?.role === 'admin') {
      fetchUsers();
    }
  }, [user]);

  const fetchPosts = async () => {
    try {
      const response = await axios.get(`${API_URL}/posts`);
      setPosts(response.data);
    } catch (error) {
      console.error('Error fetching posts:', error);
    }
  };

  const fetchUserProfile = async () => {
    try {
      const response = await axios.get(`${API_URL}/profile`);
      setUser(response.data);
      setProfileData({ name: response.data.name, bio: response.data.bio || '' });
    } catch (error) {
      console.error('Error fetching profile:', error);
    }
  };

  const fetchUsers = async () => {
    try {
      const response = await axios.get(`${API_URL}/users`);
      setUsers(response.data);
    } catch (error) {
      console.error('Error fetching users:', error);
    }
  };

  const fetchComments = async (postId) => {
    try {
      const response = await axios.get(`${API_URL}/comments/${postId}`);
      setComments(response.data);
    } catch (error) {
      console.error('Error fetching comments:', error);
    }
  };

  const handleLogin = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const response = await axios.post(`${API_URL}/login`, loginData);
      const { token, user } = response.data;
      localStorage.setItem('token', token);
      axios.defaults.headers.common['Authorization'] = token;
      setUser(user);
      setCurrentView('home');
      setLoginData({ email: '', password: '' });
    } catch (error) {
      alert('Login failed: ' + (error.response?.data?.message || 'Error'));
    } finally {
      setLoading(false);
    }
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post(`${API_URL}/register`, registerData);
      alert('Registration successful! Please login.');
      setCurrentView('login');
      setRegisterData({ name: '', email: '', password: '' });
    } catch (error) {
      alert('Registration failed: ' + (error.response?.data?.message || 'Error'));
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.removeItem('token');
    delete axios.defaults.headers.common['Authorization'];
    setUser(null);
    setCurrentView('home');
    setSelectedPost(null);
  };

  const handleCreatePost = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      await axios.post(`${API_URL}/posts`, formData);
      setFormData({ title: '', content: '', image: '' });
      fetchPosts();
      setCurrentView('home');
      alert('Post created successfully!');
    } catch (error) {
      alert('Failed to create post: ' + (error.response?.data?.message || 'Error'));
    } finally {
      setLoading(false);
    }
  };

  const handleDeletePost = async (postId) => {
    if (!window.confirm('Are you sure you want to delete this post?')) return;
    try {
      await axios.delete(`${API_URL}/posts/${postId}`);
      fetchPosts();
      alert('Post deleted successfully!');
    } catch (error) {
      alert('Failed to delete post: ' + (error.response?.data?.message || 'Error'));
    }
  };

  const handleUpdateProfile = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const response = await axios.put(`${API_URL}/profile`, profileData);
      setUser(response.data);
      alert('Profile updated successfully!');
      setCurrentView('profile');
    } catch (error) {
      alert('Failed to update profile: ' + (error.response?.data?.message || 'Error'));
    } finally {
      setLoading(false);
    }
  };

  const handleUserStatus = async (userId, currentStatus) => {
    try {
      await axios.put(`${API_URL}/users/${userId}/status`, { isActive: !currentStatus });
      fetchUsers();
      alert(`User ${!currentStatus ? 'activated' : 'deactivated'} successfully!`);
    } catch (error) {
      alert('Failed to update user status');
    }
  };

  const handleAddComment = async (e) => {
    e.preventDefault();
    if (!commentText.trim()) return;
    setLoading(true);
    try {
      await axios.post(`${API_URL}/comments/${selectedPost._id}`, { content: commentText });
      setCommentText('');
      fetchComments(selectedPost._id);
    } catch (error) {
      alert('Failed to add comment');
    } finally {
      setLoading(false);
    }
  };

  const handleDeleteComment = async (commentId) => {
    if (!window.confirm('Delete this comment?')) return;
    try {
      await axios.delete(`${API_URL}/comments/${commentId}`);
      fetchComments(selectedPost._id);
    } catch (error) {
      alert('Failed to delete comment');
    }
  };

  const viewPost = (post) => {
    setSelectedPost(post);
    fetchComments(post._id);
    setCurrentView('postDetail');
  };

  // ============= NAVIGATION MENU =============
  // GUEST: Home, About, Contact, Register, Login
  // ADMIN: Home, About, Write, Profile, Admin, Logout
  // MEMBER: Home, About, Write, Profile, Logout

  const renderNav = () => {
    if (!user) {
      // GUEST MENU
      return (
        <header>
          <h1>
            <img src="/images/Hot-Wheels-Emblem.png" alt="Hot Wheels" width="60" />
            Hot Wheels Blog
          </h1>
          <nav>
            <ul>
              <li><button onClick={() => { setCurrentView('home'); setSelectedPost(null); }} className={currentView === 'home' ? 'active' : ''}>Home</button></li>
              <li><button onClick={() => setCurrentView('about')} className={currentView === 'about' ? 'active' : ''}>About</button></li>
              <li><button onClick={() => setCurrentView('contact')} className={currentView === 'contact' ? 'active' : ''}>Contact</button></li>
              <li><button onClick={() => setCurrentView('register')} className={currentView === 'register' ? 'active' : ''}>Register</button></li>
              <li><button onClick={() => setCurrentView('login')} className={currentView === 'login' ? 'active' : ''}>Login</button></li>
            </ul>
          </nav>
        </header>
      );
    } else if (user.role === 'admin') {
      // ADMIN MENU: Home, About, Write, Profile, Admin, Logout
      return (
        <header>
          <h1>
            <img src="/images/Hot-Wheels-Emblem.png" alt="Hot Wheels" width="60" />
            Hot Wheels Blog - Admin
          </h1>
          <nav>
            <ul>
              <li><button onClick={() => { setCurrentView('home'); setSelectedPost(null); }} className={currentView === 'home' ? 'active' : ''}>Home</button></li>
              <li><button onClick={() => setCurrentView('about')} className={currentView === 'about' ? 'active' : ''}>About</button></li>
              <li><button onClick={() => setCurrentView('write')} className={currentView === 'write' ? 'active' : ''}>Write</button></li>
              <li><button onClick={() => setCurrentView('profile')} className={currentView === 'profile' ? 'active' : ''}>Profile</button></li>
              <li><button onClick={() => setCurrentView('admin')} className={currentView === 'admin' ? 'active' : ''}>Admin</button></li>
              <li><button onClick={handleLogout}>Logout</button></li>
              <li><span style={{ color: '#ff9800' }}>Welcome, {user.name} (Admin)</span></li>
            </ul>
          </nav>
        </header>
      );
    } else {
      // MEMBER MENU: Home, About, Write, Profile, Logout
      return (
        <header>
          <h1>
            <img src="/images/Hot-Wheels-Emblem.png" alt="Hot Wheels" width="60" />
            Hot Wheels Blog
          </h1>
          <nav>
            <ul>
              <li><button onClick={() => { setCurrentView('home'); setSelectedPost(null); }} className={currentView === 'home' ? 'active' : ''}>Home</button></li>
              <li><button onClick={() => setCurrentView('about')} className={currentView === 'about' ? 'active' : ''}>About</button></li>
              <li><button onClick={() => setCurrentView('write')} className={currentView === 'write' ? 'active' : ''}>Write</button></li>
              <li><button onClick={() => setCurrentView('profile')} className={currentView === 'profile' ? 'active' : ''}>Profile</button></li>
              <li><button onClick={handleLogout}>Logout</button></li>
              <li><span style={{ color: '#ff9800' }}>Welcome, {user.name}</span></li>
            </ul>
          </nav>
        </header>
      );
    }
  };

  // Home Page
  const renderHome = () => (
    <div className="container">
      <section className="hero page-border">
        <h2>Welcome to My Hot Wheels Blog</h2>
        <p>Share your passion for collecting Hot Wheels cars, from rare finds to classic models!</p>
        <img src="/images/collection.webp" alt="A collection of Hot Wheels cars" />
      </section>

      <section className="page-border">
        <h2>Latest Posts</h2>
        {posts.length === 0 ? (
          <p style={{ textAlign: 'center' }}>No posts yet. Be the first to create a post!</p>
        ) : (
          <div className="preview">
            {posts.map(post => (
              <div key={post._id} className="card" onClick={() => viewPost(post)} style={{ cursor: 'pointer' }}>
                {post.image && <img src={post.image} alt={post.title} style={{ width: '100%', borderRadius: '8px', marginBottom: '10px' }} />}
                <h3>{post.title}</h3>
                <p>{post.content.substring(0, 100)}...</p>
                <div style={{ marginTop: '10px', fontSize: '12px', color: '#666' }}>
                  By: {post.author?.name} | {new Date(post.createdAt).toLocaleDateString()}
                </div>
                {(user?.role === 'admin' || (user && post.author?._id === user.id)) && (
                  <button
                    onClick={(e) => { e.stopPropagation(); handleDeletePost(post._id); }}
                    style={{
                      marginTop: '10px',
                      padding: '5px 10px',
                      backgroundColor: '#d32f2f',
                      color: 'white',
                      border: 'none',
                      borderRadius: '4px',
                      cursor: 'pointer'
                    }}
                  >
                    Delete Post
                  </button>
                )}
              </div>
            ))}
          </div>
        )}
      </section>

      <section className="preview page-border">
        <div className="card">
          <h4>My Journey</h4>
          <p>How I started collecting Hot Wheels and tips for beginners.</p>
        </div>
        <div className="card">
          <h4>Resources</h4>
          <p>Tools and sites for collectors to find rare cars.</p>
        </div>
        <div className="card">
          <h4>Join Me</h4>
          <p>Be part of the Hot Wheels community!</p>
        </div>
      </section>
    </div>
  );

  // Post Detail Page
  const renderPostDetail = () => (
    <div className="container">
      <button onClick={() => { setCurrentView('home'); setSelectedPost(null); }} style={{ marginBottom: '20px', padding: '10px 20px', backgroundColor: '#ff9800', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>← Back to Home</button>

      <article className="page-border" style={{ padding: '30px', marginBottom: '30px' }}>
        {selectedPost.image && <img src={selectedPost.image} alt={selectedPost.title} style={{ width: '100%', borderRadius: '8px', marginBottom: '20px' }} />}
        <h1 style={{ color: '#ff3d00' }}>{selectedPost.title}</h1>
        <div style={{ marginBottom: '20px', color: '#666' }}>
          By: {selectedPost.author?.name} | {new Date(selectedPost.createdAt).toLocaleDateString()}
        </div>
        <div style={{ lineHeight: '1.8', fontSize: '1.1rem' }}>
          {selectedPost.content.split('\n').map((para, i) => <p key={i}>{para}</p>)}
        </div>
        {(user?.role === 'admin' || (user && selectedPost.author?._id === user.id)) && (
          <button onClick={() => handleDeletePost(selectedPost._id)} style={{ marginTop: '20px', padding: '10px 20px', backgroundColor: '#d32f2f', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}>
            Delete Post
          </button>
        )}
      </article>

      <div className="page-border" style={{ padding: '30px' }}>
        <h3 style={{ color: '#ff3d00', marginBottom: '20px' }}>Comments ({comments.length})</h3>

        {user && (
          <form onSubmit={handleAddComment} style={{ marginBottom: '30px' }}>
            <textarea
              value={commentText}
              onChange={(e) => setCommentText(e.target.value)}
              placeholder="Write a comment..."
              rows="3"
              style={{ width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ddd', marginBottom: '10px' }}
              required
            />
            <button type="submit" disabled={loading} style={{ padding: '10px 20px', backgroundColor: '#ff9800', border: 'none', borderRadius: '5px', cursor: 'pointer' }}>
              Post Comment
            </button>
          </form>
        )}

        {comments.length === 0 ? (
          <p>No comments yet. Be the first to comment!</p>
        ) : (
          comments.map(comment => (
            <div key={comment._id} style={{ borderBottom: '1px solid #eee', padding: '15px 0' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px' }}>
                <strong>{comment.author?.name}</strong>
                <span style={{ fontSize: '12px', color: '#666' }}>{new Date(comment.createdAt).toLocaleDateString()}</span>
              </div>
              <p>{comment.content}</p>
              {(user?._id === comment.author?._id || user?.role === 'admin') && (
                <button onClick={() => handleDeleteComment(comment._id)} style={{ marginTop: '10px', padding: '5px 10px', backgroundColor: '#d32f2f', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer', fontSize: '12px' }}>
                  Delete
                </button>
              )}
            </div>
          ))
        )}
      </div>
    </div>
  );

  // Write Post Page
  const renderWritePost = () => (
    <div className="container">
      <form onSubmit={handleCreatePost} className="page-border">
        <h2 style={{ textAlign: 'center', marginBottom: '20px', color: '#ff3d00' }}>Create New Post</h2>
        <div>
          <label>Title:</label>
          <input
            type="text"
            value={formData.title}
            onChange={(e) => setFormData({ ...formData, title: e.target.value })}
            required
          />
        </div>
        <div>
          <label>Content:</label>
          <textarea
            value={formData.content}
            onChange={(e) => setFormData({ ...formData, content: e.target.value })}
            required
            rows="10"
          />
        </div>
        <div>
          <label>Image URL (optional):</label>
          <input
            type="text"
            value={formData.image}
            onChange={(e) => setFormData({ ...formData, image: e.target.value })}
            placeholder="https://example.com/image.jpg"
          />
        </div>
        <button type="submit" disabled={loading}>
          {loading ? 'Publishing...' : 'Publish Post'}
        </button>
      </form>
    </div>
  );

  // Profile Page
  const renderProfile = () => (
    <div className="container">
      <form onSubmit={handleUpdateProfile} className="page-border">
        <h2 style={{ textAlign: 'center', marginBottom: '20px', color: '#ff3d00' }}>My Profile</h2>
        <div>
          <label>Name:</label>
          <input
            type="text"
            value={profileData.name}
            onChange={(e) => setProfileData({ ...profileData, name: e.target.value })}
          />
        </div>
        <div>
          <label>Bio:</label>
          <textarea
            value={profileData.bio}
            onChange={(e) => setProfileData({ ...profileData, bio: e.target.value })}
            rows="4"
            placeholder="Tell us about your Hot Wheels collection..."
          />
        </div>
        <div>
          <label>Email: </label>
          <span>{user?.email}</span>
        </div>
        <div>
          <label>Role: </label>
          <span>{user?.role === 'admin' ? 'Administrator' : 'Member'}</span>
        </div>
        <button type="submit" disabled={loading}>
          {loading ? 'Updating...' : 'Update Profile'}
        </button>
      </form>
    </div>
  );

  // Admin Panel
  const renderAdminPanel = () => (
    <div className="container">
      <section className="page-border" style={{ padding: '20px' }}>
        <h2 style={{ color: '#ff3d00', marginBottom: '20px' }}>Admin Panel - User Management</h2>
        <div style={{ overflowX: 'auto' }}>
          <table className="resources" style={{ width: '100%' }}>
            <thead>
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Role</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {users.map(userItem => (
                <tr key={userItem._id}>
                  <td>{userItem.name}</td>
                  <td>{userItem.email}</td>
                  <td>{userItem.role}</td>
                  <td>
                    <span style={{
                      padding: '4px 8px',
                      borderRadius: '4px',
                      backgroundColor: userItem.isActive ? '#2ecc71' : '#e74c3c',
                      color: 'white'
                    }}>
                      {userItem.isActive ? 'Active' : 'Inactive'}
                    </span>
                  </td>
                  <td>
                    <button
                      onClick={() => handleUserStatus(userItem._id, userItem.isActive)}
                      style={{
                        padding: '5px 10px',
                        backgroundColor: userItem.isActive ? '#e74c3c' : '#2ecc71',
                        color: 'white',
                        border: 'none',
                        borderRadius: '4px',
                        cursor: 'pointer'
                      }}
                    >
                      {userItem.isActive ? 'Deactivate' : 'Activate'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </section>
    </div>
  );

  // About Page
  const renderAbout = () => (
    <div className="container">
      <section className="page-border">
        <h2>What I Love About Hot Wheels</h2>
        <p>Collecting Hot Wheels brings joy to my life, especially discovering rare and unique cars. The craftsmanship and nostalgia make it a fun and memorable hobby.</p>
      </section>

      <section className="page-border">
        <h2>My Hot Wheels Journey</h2>
        <ol>
          <li>First Hot Wheel: K.I.T.T</li>
          <li>Started collecting: December 27, 2025</li>
          <li>Finding nice cars to add to my collection</li>
          <li>Currently, I have 50 pieces in my room</li>
        </ol>
        <center>
          <h2>My Favorite Hot Wheels: "Formula 1" – One of the hardest to find!</h2>
          <img src="/images/f1.webp" alt="Hot Wheels Formula 1" width="200" />
        </center>
      </section>

      <div className="quiz-container page-border">
        <h2>Hot Wheels Quiz!</h2>
        <QuizComponent />
      </div>

      <blockquote className="page-border">
        <h3><strong><center>"Collecting Hot Wheels is not just about the cars, it's about the memories and connections you make along the way."</center></strong></h3>
      </blockquote>
    </div>
  );

  // Quiz Component
  const QuizComponent = () => {
    const [currentQuestion, setCurrentQuestion] = useState(0);
    const [score, setScore] = useState(0);
    const [showResult, setShowResult] = useState(false);
    const [selectedAnswer, setSelectedAnswer] = useState(null);

    const questions = [
      {
        question: "What year was Hot Wheels founded?",
        options: ["1968", "1975", "1982", "1990"],
        correct: 0
      },
      {
        question: "What was the first Hot Wheels car ever made?",
        options: ["Twin Mill", "Custom Camaro", "Sweet 16", "Bone Shaker"],
        correct: 1
      },
      {
        question: "Which company manufactures Hot Wheels?",
        options: ["Hasbro", "Lego", "Mattel", "Bandai"],
        correct: 2
      },
      {
        question: "What color is the famous 'Treasure Hunt' logo?",
        options: ["Red", "Blue", "Green", "Yellow"],
        correct: 0
      }
    ];

    const handleAnswer = (selectedIdx) => {
      setSelectedAnswer(selectedIdx);
    };

    const handleNext = () => {
      if (selectedAnswer === questions[currentQuestion].correct) {
        setScore(score + 1);
      }
      setSelectedAnswer(null);
      if (currentQuestion + 1 < questions.length) {
        setCurrentQuestion(currentQuestion + 1);
      } else {
        setShowResult(true);
      }
    };

    if (showResult) {
      return (
        <div className="quiz-complete">
          <h3>Quiz Complete!</h3>
          <p>Your score: {score} out of {questions.length}</p>
          <p>{score === questions.length ? "Perfect! You're a Hot Wheels expert!" : "Good try! Keep collecting!"}</p>
        </div>
      );
    }

    return (
      <div>
        <h3 id="quizQuestion">{questions[currentQuestion].question}</h3>
        <div className="options">
          {questions[currentQuestion].options.map((option, idx) => (
            <div
              key={idx}
              className={`option ${selectedAnswer === idx ? 'selected' : ''}`}
              onClick={() => handleAnswer(idx)}
            >
              {option}
            </div>
          ))}
        </div>
        <button onClick={handleNext} disabled={selectedAnswer === null}>
          {currentQuestion + 1 === questions.length ? 'Finish' : 'Next'}
        </button>
      </div>
    );
  };

  // Contact Page
  const renderContact = () => {
    const ContactFormComponent = () => {
      const [contactData, setContactData] = useState({ name: '', email: '', message: '' });
      const handleContactSubmit = (e) => {
        e.preventDefault();
        alert('Message sent! We\'ll get back to you soon.');
        setContactData({ name: '', email: '', message: '' });
      };
      return (
        <form onSubmit={handleContactSubmit}>
          <h2 style={{ textAlign: 'center', marginBottom: '20px', color: '#ff3d00' }}>Contact Us</h2>
          <div>
            <label>Name:</label>
            <input type="text" value={contactData.name} onChange={(e) => setContactData({ ...contactData, name: e.target.value })} required />
          </div>
          <div>
            <label>Email:</label>
            <input type="email" value={contactData.email} onChange={(e) => setContactData({ ...contactData, email: e.target.value })} required />
          </div>
          <div>
            <label>Message:</label>
            <textarea rows="5" value={contactData.message} onChange={(e) => setContactData({ ...contactData, message: e.target.value })} required />
          </div>
          <button type="submit">Send Message</button>
          <div style={{ marginTop: '30px', textAlign: 'center' }}>
            <h3>Our Information</h3>
            <p>Email: support@hotwheelsblog.com</p>
            <p>Phone: (123) 456-7890</p>
            <p>Address: 123 Hot Wheels Lane, Collector City, USA</p>
          </div>
        </form>
      );
    };

    return (
      <div className="container">
        <div className="page-border">
          <ContactFormComponent />
        </div>

        <section className="map-section page-border">
          <center>
            <h2>THIS MAP IS A PLACEHOLDER ONLY</h2>
          </center>
          <img src="/images/OIP (8).webp" alt="Hot Wheels Map" style={{ height: '180px' }} />
        </section>

        <section className="resources page-border">
          <h2 style={{ color: '#ff3d00' }}>Hot Wheels Resources</h2>
          <table border="1" width="100%">
            <thead>
              <tr>
                <th>Resource Name</th>
                <th>Description</th>
              </tr>
            </thead>
            <tbody>
              <tr>
                <td>Hot Wheels Official Website</td>
                <td>Visit for the latest car releases and updates.</td>
              </tr>
              <tr>
                <td>Hot Wheels Collector's Guide</td>
                <td>A guide for collectors, including rarity and value of cars.</td>
              </tr>
              <tr>
                <td>eBay Hot Wheels Auctions</td>
                <td>Find rare Hot Wheels on eBay for buying and selling.</td>
              </tr>
            </tbody>
          </table>
        </section>
      </div>
    );
  };

  // Login Page
  const renderLogin = () => (
    <div className="container">
      <form onSubmit={handleLogin} className="page-border">
        <h2 style={{ textAlign: 'center', marginBottom: '20px', color: '#ff3d00' }}>Login</h2>
        <div>
          <label>Email:</label>
          <input
            type="email"
            value={loginData.email}
            onChange={(e) => setLoginData({ ...loginData, email: e.target.value })}
            required
          />
        </div>
        <div>
          <label>Password:</label>
          <input
            type="password"
            value={loginData.password}
            onChange={(e) => setLoginData({ ...loginData, password: e.target.value })}
            required
          />
        </div>
        <button type="submit" disabled={loading}>
          {loading ? 'Logging in...' : 'Login'}
        </button>
        <p style={{ marginTop: '15px', textAlign: 'center' }}>
          Don't have an account? <button onClick={() => setCurrentView('register')} style={{ background: 'none', border: 'none', color: '#ff9800', cursor: 'pointer' }}>Register here</button>
        </p>
      </form>
    </div>
  );

  // Register Page
  const renderRegister = () => (
    <div className="container">
      <section style={{ textAlign: 'center' }}>
        <img src="/images/hw.png" alt="Hot Wheels collection display" width="150" height="50" />
        <h3>Sign up to receive updates, tips, and learning resources about Hot Wheels collecting.</h3>
      </section>
      <form onSubmit={handleRegister} className="page-border">
        <h2 style={{ textAlign: 'center', marginBottom: '20px', color: '#ff3d00' }}>Register</h2>
        <div>
          <label>Name:</label>
          <input
            type="text"
            value={registerData.name}
            onChange={(e) => setRegisterData({ ...registerData, name: e.target.value })}
            required
          />
        </div>
        <div>
          <label>Email:</label>
          <input
            type="email"
            value={registerData.email}
            onChange={(e) => setRegisterData({ ...registerData, email: e.target.value })}
            required
          />
        </div>
        <div>
          <label>Password:</label>
          <input
            type="password"
            value={registerData.password}
            onChange={(e) => setRegisterData({ ...registerData, password: e.target.value })}
            required
          />
        </div>
        <button type="submit" disabled={loading}>
          {loading ? 'Registering...' : 'Register'}
        </button>
        <p style={{ marginTop: '15px', textAlign: 'center' }}>
          Already have an account? <button onClick={() => setCurrentView('login')} style={{ background: 'none', border: 'none', color: '#ff9800', cursor: 'pointer' }}>Login here</button>
        </p>
      </form>
    </div>
  );

  return (
    <div>
      {renderNav()}
      {currentView === 'home' && renderHome()}
      {currentView === 'postDetail' && renderPostDetail()}
      {currentView === 'about' && renderAbout()}
      {currentView === 'contact' && renderContact()}
      {currentView === 'write' && renderWritePost()}
      {currentView === 'profile' && renderProfile()}
      {currentView === 'admin' && user?.role === 'admin' && renderAdminPanel()}
      {currentView === 'login' && !user && renderLogin()}
      {currentView === 'register' && !user && renderRegister()}

      <footer>
        <p>© 2024 Hot Wheels Blog | Passion for Collecting | All Rights Reserved</p>
      </footer>
    </div>
  );
}

export default App;
